import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const m=JSON.parse('{"title":"大纲生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/大纲生成.md","filePath":"mumuainovel/大纲生成.md","lastUpdated":1778811657000}'),e={name:"mumuainovel/大纲生成.md"};function t(i,s,c,o,u,q){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="大纲生成" tabindex="-1">大纲生成 <a class="header-anchor" href="#大纲生成" aria-label="Permalink to &quot;大纲生成&quot;">​</a></h1><blockquote><p>模板键: <code>OUTLINE_CREATE</code> 分类: 大纲生成 描述: 根据项目信息生成完整的章节大纲 参数: [&quot;title&quot;, &quot;theme&quot;, &quot;genre&quot;, &quot;chapter_count&quot;, &quot;narrative_perspective&quot;, &quot;target_words&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;, &quot;characters_info&quot;, &quot;requirements&quot;, &quot;mcp_references&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是经验丰富的小说作家和编剧，擅长为{genre}类型小说设计具有强人物驱动的开篇结构。你的核心原则：让角色在行动中自然出场，不安排“示范性”亮相。设定通过角色的眼睛和身体来呈现，不通过旁白铺设。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【创作任务】</span></span>
<span class="line"><span>为小说《{title}》生成开篇{chapter_count}章的大纲。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【重要说明】</span></span>
<span class="line"><span>这是开局阶段。开局的任务不是“介绍”，是让读者撞见一个人正在做一件事。设定和世界观从这件事的缝隙里漏出来，角色在做事的过程中被读者认识。</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>开篇章节数：{chapter_count}</span></span>
<span class="line"><span>叙事视角：{narrative_perspective}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;worldview priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span>&lt;/worldview&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;characters priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【角色信息】</span></span>
<span class="line"><span>{characters_info}</span></span>
<span class="line"><span>&lt;/characters&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;mcp_context priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>{mcp_references}</span></span>
<span class="line"><span>&lt;/mcp_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;requirements priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【其他要求】</span></span>
<span class="line"><span>{requirements}</span></span>
<span class="line"><span>&lt;/requirements&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回包含{chapter_count}个章节对象的JSON数组：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[</span></span>
<span class="line"><span>  {{</span></span>
<span class="line"><span>   &quot;chapter_number&quot;: 1,</span></span>
<span class="line"><span>   &quot;title&quot;: &quot;章节标题&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;summary&quot;: &quot;章节概要（500-1000字）：按事件发生顺序描述本章内容。只写谁做了什么、发生了什么、结果是什么。禁止使用&#39;因为&#39;&#39;所以&#39;&#39;这意味着&#39;&#39;体现出&#39;。不分析角色动机，不标注情感节点。写成连贯的自然段落，不编号，不分段标注&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;scenes&quot;: [</span></span>
<span class="line"><span>     &quot;场景1：地点，谁在场，发生什么（不标注场景功能）&quot;,</span></span>
<span class="line"><span>     &quot;场景2：地点，谁在场，发生什么（不标注场景功能）&quot;,</span></span>
<span class="line"><span>     &quot;场景3：地点，谁在场，发生什么（不标注场景功能）&quot;</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;characters&quot;: [</span></span>
<span class="line"><span>     {{&quot;name&quot;: &quot;角色名&quot;, &quot;type&quot;: &quot;character&quot;}},</span></span>
<span class="line"><span>     {{&quot;name&quot;: &quot;组织名&quot;, &quot;type&quot;: &quot;organization&quot;}}</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;key_points&quot;: [</span></span>
<span class="line"><span>     &quot;本章最关键的一个动作或选择（只描述动作，不解释原因）&quot;,</span></span>
<span class="line"><span>     &quot;本章最核心的一个变化（关系变化、认知变化、信息变化或局势变化，只描述变化内容）&quot;</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;emotion&quot;: &quot;本章主要角色的情绪状态和转变（不画完整弧线。只写起点和终点之间最明显的一两个起伏。允许断点，允许残留。格式如：压抑→某句话触发了短暂的暴躁→收住，或：茫然→注意到一个细节→不安但不确认）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;goal&quot;: &quot;本章主要角色的行动目标（必须是角色当下能感知到的具体目标，不是抽象概括。例如：不是&#39;她想活下去&#39;，而是&#39;她想在巡逻队转过街角之前把那个东西藏好&#39;）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;decision_basis&quot;: &quot;主要决策的触发因素（不是性格总结。写角色在场景中具体看到/听到/感觉到了什么，导致他做出这个决定。格式：&#39;看到X→决定Y&#39;。禁止写&#39;因为她是一个坚韧的人&#39;）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;foreshadow_plant&quot;: [&quot;本章新埋的伏笔（预期作用）&quot;]</span></span>
<span class="line"><span> }}</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【characters字段说明】</span></span>
<span class="line"><span>- type为&quot;character&quot;表示个人角色，type为&quot;organization&quot;表示组织/势力/门派/帮派/公司/机构等</span></span>
<span class="line"><span>- 必须区分角色和组织，不要把组织当作角色</span></span>
<span class="line"><span>- 故事中出现的帮派、门派、公司、政府机构、学校、家族等组织/势力实体都必须列入characters，并标记type为&quot;organization&quot;</span></span>
<span class="line"><span>- 每章characters中应包含该章涉及的组织/势力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式规范】</span></span>
<span class="line"><span>- 纯JSON数组输出</span></span>
<span class="line"><span>- 字段结构必须一致</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【JSON格式特别要求】</span></span>
<span class="line"><span>✅ 字符串值必须在同一行内完成，禁止跨行</span></span>
<span class="line"><span>✅ 字符串值中的换行用转义的 \\\\n 表示，不插入真实换行符</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【开篇核心规则】</span></span>
<span class="line"><span>❗每一章必须包含：</span></span>
<span class="line"><span>1. 一个角色正在做的具体的事</span></span>
<span class="line"><span>2. 一个阻碍这件事的因素（人、环境、信息缺失、规则）</span></span>
<span class="line"><span>3. 角色对阻碍做出的反应（行动或选择，包括选择暂时不做反应）</span></span>
<span class="line"><span>4. 做完反应后，有什么和开头不一样了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗禁止写成：</span></span>
<span class="line"><span>- 角色站在某处让旁白介绍背景</span></span>
<span class="line"><span>- 设定堆叠（连续多段只描述世界观而不推进人物行动）</span></span>
<span class="line"><span>- 角色“准备行动”但整章没动</span></span>
<span class="line"><span>- 一章内解决核心矛盾</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【开篇结构要求】</span></span>
<span class="line"><span>1. 第1章：角色正在做某件事→遇到阻碍→做出反应→产生变化（变化可以小，但必须有。不是“英雄踏上征途”，是“她发现自己手里的东西不对劲”）</span></span>
<span class="line"><span>2. 第2章：角色对第1章的变化做出下一步行动→遇到新的阻碍或认知变化</span></span>
<span class="line"><span>3. 第3章及以后：冲突从具体事件中逐步扩散，不要突然跳跃到宏大叙事</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【人物出场规则】</span></span>
<span class="line"><span>❗角色必须在行动中出场。禁止任何形式的“人物介绍段落”——不写外貌总结，不写性格概括，不写过去经历综述。让角色的外貌、性格、经历从他正在做的事里漏出来</span></span>
<span class="line"><span>❗每章至少有一个角色主动推动剧情</span></span>
<span class="line"><span>❗允许次要角色只出现一个动作、一句话、一个没做完的举动</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【节奏控制】</span></span>
<span class="line"><span>- 每章有变化，但不一定解决问题。允许新问题比答案多</span></span>
<span class="line"><span>- 信息逐步释放，通过角色的感知和行动来传递，不通过总结性的叙述段落</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 数量精确</span></span>
<span class="line"><span>✅ chapter_number编号从1开始递增</span></span>
<span class="line"><span>✅ summary 500-1000字</span></span>
<span class="line"><span>✅ 符合类型与主题</span></span>
<span class="line"><span>✅ 是开局而非完整闭环——不求解决核心矛盾，求让人知道主角屁股下面坐着什么东西在冒烟</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown或代码块</span></span>
<span class="line"><span>❌ 使用特殊符号</span></span>
<span class="line"><span>❌ 一章解决核心矛盾</span></span>
<span class="line"><span>❌ 无冲突或无人物行动</span></span>
<span class="line"><span>❌ 在summary中使用&quot;因为&quot;&quot;所以&quot;&quot;这意味着&quot;&quot;体现出&quot;&quot;代表着&quot;</span></span>
<span class="line"><span>❌ 在scenes中标注场景功能（如&quot;冲突升级&quot;&quot;情感转折&quot;&quot;人物出场介绍&quot;）</span></span>
<span class="line"><span>❌ 连续两章key_points内容雷同</span></span>
<span class="line"><span>❌ summary写成&quot;开场情境/人物目标/冲突来源/关键互动/转折变化/结果变化&quot;的编号格式——必须写成连贯的自然段落</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const _=n(e,[["render",t]]);export{m as __pageData,_ as default};
